#!/usr/bin/perl
use strict;
use warnings;
use CGI qw(:standard);
use File::Basename;

my $log_dir = '/path/to/logs';  # Set your log directory
my $cgi = CGI->new;

print $cgi->header('text/plain');

my $filename = $cgi->param('logfile');

# Validate the filename
if ($filename && $filename =~ /^[\w\-.]+$/) {
    my $filepath = "$log_dir/$filename";
    
    if (-e $filepath && -f $filepath) {
        open(my $fh, '<', $filepath) or die "Cannot open file: $!";
        while (my $line = <$fh>) {
            print $line;
        }
        close($fh);
    } else {
        print "File does not exist or is not a regular file.";
    }
} else {
    print "Invalid filename.";
}